import { forwardRef } from 'react';

export interface ArvoBreadcrumbItem {
  label: string;
  href?: string;
  icon?: string;
}

export interface ArvoBreadcrumbProps {
  items: ArvoBreadcrumbItem[];
  separator?: string;
  isDisabled?: boolean;
  isLoading?: boolean;
  ariaLabel?: string;
  onNavigate?: (event: { href: string; index: number; label: string }) => void;
  className?: string;
}

const ArvoBreadcrumb = forwardRef<HTMLElement, ArvoBreadcrumbProps>(
  function ArvoBreadcrumb(
    {
      items,
      isDisabled = false,
      isLoading = false,
      ariaLabel = 'Breadcrumb',
      onNavigate,
      className,
    },
    ref
  ) {
    const classes = [
      'arvo-bc',
      isDisabled ? 'is-disabled' : '',
      isLoading ? 'loading' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;
    const lastIndex = items.length - 1;

    const handleClick = (
      e: React.MouseEvent<HTMLAnchorElement>,
      item: ArvoBreadcrumbItem,
      index: number
    ) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }

      if (onNavigate && item.href) {
        onNavigate({ href: item.href, index, label: item.label });
      }
    };

    return (
      <nav
        ref={ref}
        aria-label={ariaLabel}
        aria-busy={isLoading ? true : undefined}
        className={classes}
      >
        <ol className="arvo-bc__list">
          {items.map((item, index) => {
            const isLast = index === lastIndex;
            const isIconOnly = !!item.icon && !item.label;

            return (
              <li key={index} className="arvo-bc__item">
                {isLast ? (
                  <span className="arvo-bc__lbl" aria-current="page">
                    {item.label}
                  </span>
                ) : (
                  <a
                    className="arvo-bc__lnk"
                    href={isDisabled ? undefined : item.href}
                    aria-disabled={isDisabled ? true : undefined}
                    aria-label={isIconOnly ? item.label || 'Home' : undefined}
                    tabIndex={isDisabled ? 0 : undefined}
                    onClick={(e) => handleClick(e, item, index)}
                  >
                    {item.icon && (
                      <span
                        className={`arvo-bc__ico o9con o9con-${item.icon}`}
                        aria-hidden="true"
                      />
                    )}
                    {item.label && item.label}
                  </a>
                )}
              </li>
            );
          })}
        </ol>
      </nav>
    );
  }
);

export default ArvoBreadcrumb;
